import { useState, useMemo } from "react";
import UserInfoPage from "./UserInfoPage";
import InstructionPage from "./InstructionPage";
import EvaluationPage from "./EvaluationPage";

function shuffleArray<T>(array: T[]): T[] {
  return array
    .map((value) => ({ value, sort: Math.random() }))
    .sort((a, b) => a.sort - b.sort)
    .map(({ value }) => value);
}

const IMAGE_DATA = {
  image_path: "/images/scholar.png",
  level2: {
    caption:
      "This brown, T-shaped robe with wide sleeves shows noticeable signs of age and wear.",
  },
  level3: {
    caption:
      "This brown, T-shaped garment with wide sleeves shows noticeable signs of age and wear from Korea's clothes category.",
  },
  level4: {
    caption:
      "This aged, brown Aekjureumpo, a T-shaped garment with wide sleeves from Korea, shows signs of wear consistent with its historical use as a ritual robe worn by Buddhist monks.",
  },
  level1: {
    caption:
      "A modern, brightly colored Buddhist monk's robe demonstrates a contemporary adaptation of traditional Korean ritual garments.",
  },
};

export default function App() {
  const [step, setStep] = useState<
    "userinfo" | "instruction" | "evaluation" | "done"
  >("userinfo");

  const [userInfo, setUserInfo] = useState({
    gender: "",
    email: "",
    consent: false,
    country: "",
  });

  // level2~4을 랜덤하게 섞은 caption 리스트 (한 번만 섞이도록 useMemo)
  const shuffledCaptions = useMemo(
    () =>
      shuffleArray([
        { level: "level2", caption: IMAGE_DATA.level2.caption },
        { level: "level3", caption: IMAGE_DATA.level3.caption },
        { level: "level4", caption: IMAGE_DATA.level4.caption },
      ]),
    []
  );

  const handleEvaluationSubmit = async (scores: any[]) => {
    // 랜덤으로 보여준 level에 맞춰 점수 맵핑
    const finalJson: any = {};

    shuffledCaptions.forEach((item, idx) => {
      finalJson[item.level] = {
        caption: item.caption,
        Cultural_Appropriateness: scores[idx].cultural,
        Visual_Detail: scores[idx].visual,
        Hallucination: scores[idx].hallucination,
      };
    });

    // level1은 평가 안 하니까 그냥 붙이기
    finalJson["level1"] = {
      caption: IMAGE_DATA.level1.caption,
    };

    const payload = {
      email: userInfo.email,
      gender: userInfo.gender,
      country: userInfo.country,
      image_path: IMAGE_DATA.image_path,
      json_data: finalJson,
    };

    console.log("📦 서버로 전송될 JSON:", payload);

    try {
      const response = await fetch("http://localhost:8000/api/evaluate/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        console.log("✅ 저장 완료");
        setStep("done");
      } else {
        console.error("❌ 서버 오류", await response.text());
        alert("서버 오류 발생");
      }
    } catch (error) {
      console.error("❌ 네트워크 오류", error);
      alert("서버 연결 실패");
    }
  };

  return (
    <>
      {step === "userinfo" && (
        <UserInfoPage
          userInfo={userInfo}
          setUserInfo={setUserInfo}
          onNext={(country) => {
            setUserInfo({ ...userInfo, country });
            setStep("instruction");
          }}
        />
      )}

      {step === "instruction" && (
        <InstructionPage onStart={() => setStep("evaluation")} />
      )}

      {step === "evaluation" && (
        <EvaluationPage
          imageUrl={IMAGE_DATA.image_path}
          captions={shuffledCaptions}
          onSubmit={handleEvaluationSubmit}
        />
      )}

      {step === "done" && (
        <div className="container">
          <h2>✅ All evaluations completed!</h2>
        </div>
      )}
    </>
  );
}
